#include <iostream>
#include <string>

class Connection {
private:
    std::string host;
    int port;
    bool open;

public:
    Connection(std::string h, int p) {
        host = h;
        port = p;
        open = false;
    }

    ~Connection() {
        std::cout << "Connection closed." << std::endl;
    }

    void connect() {
        open = true;
        std::cout << "Connected to " << host << ":" << port << std::endl;
    }

    bool isOpen() {
        return open;
    }
};

int main() {
    Connection c("192.168.1.1", 8080);
    c.connect();
    std::cout << c.isOpen() << std::endl; // 1
    return 0;
} // destructor fires here

