enum class State {
    IDLE,
    CONNECTING,
    CONNECTED,
    ERROR
};

void report(State s) {
    switch (s) {
        case State::IDLE:       std::cout << "Idle" << std::endl; break;
        case State::CONNECTING: std::cout << "Connecting" << std::endl; break;
        case State::CONNECTED:  std::cout << "Connected" << std::endl; break;
        case State::ERROR:      std::cout << "Error" << std::endl; break;
    }
}

int main() {
    State current = State::CONNECTING;
    report(current);
    return 0;
}

